48. How do you run-length compress a string?

Answer

Answer: Scan each run of equal characters, append the character and run length, then continue from the next run.
Code example:

function compress(s) {
let out = '',
i = 0;
while (i < s.length) {
let j = i;
while (j < s.length && s[j] === s[i]) j++;
out += s[i] + (j - i);
i = j;
}
return out;
}

